-- K-02 Characters (4 players: 1 mafioso, 3 innocent) — سوق الدرب الأحمر
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-02'), 'صبحي', 1, 'صاحب محل بهارات في سوق الدرب الأحمر مقابل محل الدهب بتاع الحاج نبيل. راجل في الأربعينات هادي وبيسلّم على كل الناس. بيقفل محله متأخّر وبيعرف مواعيد كل التجار في السوق.', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-02'), 'نادر', 2, 'تاجر توابل في المحل اللي جنب محل الحاج نبيل. راجل في الخمسينات عصبي وصوته عالي. عنده خناقات مع نص التجار في السوق على الأماكن والإيجارات.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-02'), 'سميحة', 3, 'ست في التلاتينات محدش في السوق يعرف عنها حاجة كتير. بتيجي تزور الحاج نبيل كل فترة. ناس بتقول إنها قريبته وناس بتقول حاجة تانية.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-02'), 'أبو خالد', 4, 'صاحب القهوة اللي في أول السوق. راجل في الستينات بيعرف كل الناس وكل الأخبار. كل التجار بيقعدوا عنده بالليل يتكلّموا. عنده ديون ومشاكل مالية بس بيضحك وخلاص.', false);

-- K-04 Characters (4 players: 1 mafioso, 3 innocent) — مدرسة في بنها
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-04'), 'هشام', 1, 'الفرّاش بتاع مدرسة بنها الإعدادية بنات من ١٥ سنة. راجل في الخمسينات طيب والبنات بيحبّوه. عنده مفتاح كل الأبواب في المدرسة وبيعرف المدرسة أحسن من أي حد.', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-04'), 'سعاد', 2, 'مدرّسة عربي في المدرسة من ٥ سنين. ست في الأربعينات حازمة والبنات بيخافوا منها. متخانقة مع الناظر على تقييم الأداء وبتحس إنه ظلمها.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-04'), 'رجب', 3, 'بتاع البوفيه اللي جوّه المدرسة. راجل في التلاتينات نشيط وبيعرف كل البنات بالاسم. عنده مشاكل مع الإدارة عشان عايزين يشيلوا البوفيه ويجيبوا شركة بداله.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-04'), 'إيناس', 4, 'السكرتيرة بتاعة المدرسة. ست في التلاتينات بتعرف كل أسرار المدرسة والمدرّسين. الناظر نقلها من مكتبها الكبير لمكتب صغير وهي زعلانة أوي.', false);

-- K-06 Characters (4 players: 1 mafioso, 3 innocent) — مول في أكتوبر
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-06'), 'عاطف', 1, 'مدير الصيانة في مول "ستار بلازا" من سنتين. راجل في الأربعينات ساكت وبيشتغل كويس. عنده صلاحية على كل أنظمة المول من كاميرات وكهربا وأبواب طوارئ.', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-06'), 'حسن', 2, 'حارس الليل في المول. شاب في التلاتينات كسلان شوية وبينام في الشيفت أحياناً. عنده مشاكل مع إدارة المول على مرتّبه اللي بيتأخّر كل شهر.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-06'), 'داليا', 3, 'مديرة منطقة الألعاب في المول. بنت في العشرينات نشيطة بس بتمشي بدري أحياناً من غير ما تقول لحد. كريم ابن صاحب المول كان أمانة عندها.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-06'), 'يوسف', 4, 'صاحب كافيه في المول. راجل في الأربعينات عصبي ومتخانق مع المهندس طارق صاحب المول على الإيجار اللي زاد. هدّده قدام الناس أكتر من مرة.', false);

-- K-09 Characters (4 players: 1 mafioso, 3 innocent) — قرية في الفيوم
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-09'), 'عوض', 1, 'العطّار بتاع القرية. راجل في الخمسينات عنده محل صغير بيبيع فيه أعشاب وأدوية. الناس كانت بتشتري منه قبل ما الدكتور مجدي يفتح العيادة.', true);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-09'), 'حمدي', 2, 'ابن عمدة القرية. شاب في التلاتينات مدلّع وبيحب يتحكّم في الناس. اتخانق مع الدكتور مجدي قبل كده عشان رفض يدّيه إجازة مرضية مزوّرة.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-09'), 'أم سيد', 3, 'الداية القديمة بتاعة القرية. ست في الستينات كل الناس كانت بتروحلها قبل ما الدكتور ييجي. دلوقتي مبقاش حد بيروحلها وخسرت رزقها ومش مبسوطة.', false);
INSERT INTO case_characters (case_id, character_name, character_order, public_profile, is_mafioso) VALUES ((SELECT id FROM cases WHERE case_code = 'K-09'), 'شريف', 4, 'سواق التوكتوك اللي بيوصّل الناس من القرية للعيادة. شاب في العشرينات نشيط بس عصبي. كان عايز الدكتور يدفعله نسبة من كل مريض بيوصّله ومتخانقين.', false);
